#include <bits/stdc++.h>using namespace std; // --- FAST I/O & SHORTCUTS ---using ll = long long;using vll = vector<long long>;using vi = vector<int>;using pii = pair<int, int>; // Constantsconst ll MOD = 1e9 + 7;const ll INF = 1e18; // --- LOGIC ---void solve() {    int n;    cin >> n;    vector<int> arr(n);    for(int i=0; i<n; i++) {        cin >> arr[i];    }    int ans = INT_MAX;    for(int i=0; i<n; i++) {        ans = min(ans, abs(arr[i]));                }    cout << ans << "\n";        }// --- MAIN DRIVER ---int main() {    // Fast I/O: 10x faster input reading    ios_base::sync_with_stdio(false);    cin.tie(NULL);     int T = 1;    //cin >> T; // Comment this out if problem has NO test cases    while (T--) {        solve();    }    return 0;}